class ExampleService:
    def __init__(self):
        self.service_state = ServiceState()
        self.data_store = {}
    
    @handle_grpc_error
    def CreateItem(self, request, context):
        if not request.name:
            raise ValueError("Item name cannot be empty")
        
        if request.name in self.data_store:
            raise ValueError(f"Item '{request.name}' already exists")
        
        self.data_store[request.name] = {
            'value': request.value,
            'created_at': datetime.now().isoformat()
        }
        
        response = example_pb2.CreateItemResponse()
        response.success = True
        response.message = f"Item '{request.name}' created successfully"
        return response
    
    @handle_grpc_error
    def GetItem(self, request, context):
        if not request.name:
            raise ValueError("Item name cannot be empty")
        
        if request.name not in self.data_store:
            raise FileNotFoundError(f"Item '{request.name}' not found")
        
        item_data = self.data_store[request.name]
        
        response = example_pb2.GetItemResponse()
        response.name = request.name
        response.value = item_data['value']
        response.created_at = item_data['created_at']
        return response
    
    @handle_grpc_error
    def UpdateItem(self, request, context):
        if not request.name:
            raise ValueError("Item name cannot be empty")
        
        if request.name not in self.data_store:
            raise FileNotFoundError(f"Item '{request.name}' not found")
        
        self.data_store[request.name]['value'] = request.value
        self.data_store[request.name]['updated_at'] = datetime.now().isoformat()
        
        response = example_pb2.UpdateItemResponse()
        response.success = True
        response.message = f"Item '{request.name}' updated successfully"
        return response
    
    @handle_grpc_error
    def DeleteItem(self, request, context):
        if not request.name:
            raise ValueError("Item name cannot be empty")
        
        if request.name not in self.data_store:
            raise FileNotFoundError(f"Item '{request.name}' not found")
        
        del self.data_store[request.name]
        
        response = example_pb2.DeleteItemResponse()
        response.success = True
        response.message = f"Item '{request.name}' deleted successfully"
        return response
    
    @handle_grpc_error
    def ProcessData(self, request, context):
        if request.operation == "divide":
            if request.divisor == 0:
                raise ValueError("Division by zero is not allowed")
            result = request.dividend / request.divisor
        elif request.operation == "timeout":
            raise TimeoutError("Operation timed out while processing data")
        elif request.operation == "unimplemented":
            raise NotImplementedError("This operation is not yet implemented")
        elif request.operation == "connection":
            raise ConnectionError("Failed to connect to external service")
        else:
            raise ValueError(f"Unknown operation: {request.operation}")
        
        response = example_pb2.ProcessDataResponse()
        response.result = result
        return response
    
    @handle_grpc_error
    def GetServiceHealth(self, request, context):
        state = self.service_state.get_state()
        
        response = example_pb2.HealthResponse()
        response.status = "healthy"
        response.request_count = state['request_count']
        response.error_count = state['error_count']
        response.uptime_seconds = state['uptime_seconds']
        
        if state['last_error']:
            response.last_error = state['last_error']
        
        return response


class StreamingExampleService:
    def __init__(self):
        self.service_state = ServiceState()
    
    @handle_grpc_error
    def StreamItems(self, request, context):
        self.service_state.increment_request()
        
        try:
            for i in range(request.count):
                if i == request.fail_at_index:
                    raise ValueError(f"Intentional failure at index {i}")
                
                response = example_pb2.StreamItemResponse()
                response.index = i
                response.data = f"Item {i}"
                response.timestamp = datetime.now().isoformat()
                yield response
                
                time.sleep(0.1)
        
        except Exception as e:
            error_details = create_error_details(e, self.service_state, 'StreamItems', request)
            self.service_state.increment_error(error_details)
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details(error_details)
            raise
    
    @handle_grpc_error
    def UploadStream(self, request_iterator, context):
        self.service_state.increment_request()
        
        try:
            total_items = 0
            for request in request_iterator:
                if request.should_fail:
                    raise ValueError(f"Client requested failure at item {total_items}")
                total_items += 1
            
            response = example_pb2.UploadStreamResponse()
            response.total_items = total_items
            response.success = True
            return response
        
        except Exception as e:
            error_details = create_error_details(e, self.service_state, 'UploadStream', None)
            self.service_state.increment_error(error_details)
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details(error_details)
            return None


def serve(port=50051):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    
    example_service = ExampleService()
    streaming_service = StreamingExampleService()
    
    example_pb2_grpc.add_ExampleServiceServicer_to_server(example_service, server)
    example_pb2_grpc.add_StreamingExampleServiceServicer_to_server(streaming_service, server)
    
    server.add_insecure_port(f'[::]:{port}')
    server.start()
    
    print(f"Server started on port {port}")
    
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        print("Shutting down server...")
        server.stop(0)


if __name__ == '__main__':
    serve()